304 |     private fun recursiveLog(node: android.view.accessibility.AccessibilityNodeInfo, depth: Int) {
305 |         if (depth > 10) return // Prevent deep recursion stack overflow
306 |         val sb = StringBuilder()
307 |         repeat(depth) { sb.append("  ") }
308 |         sb.append(node.className)
309 |         if (node.viewIdResourceName != null) sb.append(" ID:${node.viewIdResourceName}")
310 |         if (node.contentDescription != null) sb.append(" Desc:${node.contentDescription}")
311 |         if (node.isClickable) sb.append(" [CLICKABLE]")
312 |         
313 |         // Log significant nodes only to save spam, or all if debugging
314 |         if (node.viewIdResourceName != null || node.isClickable) {
315 |              DebugLogger.log("UI_NODE", sb.toString())
316 |         }
317 |         
318 |         for (i in 0 until node.childCount) {
319 |             node.getChild(i)?.let { recursiveLog(it, depth + 1) }
320 |         }
321 |     }
