private fun startMonitoring() {
    if (isObserverRegistered) return

    // SEEDING: Prevent gallery spam by ignoring photos taken before this moment
    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    if (prefs.getLong("last_image_id", -1L) == -1L) {
        val projection = arrayOf(android.provider.MediaStore.Images.Media._ID)
        contentResolver.query(android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI, projection, null, null, "${android.provider.MediaStore.Images.Media._ID} DESC LIMIT 1")?.use { cursor ->
