package com.universal.app

import android.app.*
import android.content.Context
import android.content.Intent
import android.database.ContentObserver
import android.net.Uri
import android.os.Handler
import android.os.IBinder
import android.os.Looper
import android.provider.MediaStore
import androidx.core.app.NotificationCompat
import java.io.File

class ImageMonitorService : Service() {
    private val CHANNEL_ID = "ImageMonitorChannel"
    private var observer: ContentObserver? = null
    private var lastEventTime = 0L
    private var isObserverRegistered = false

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        createNotificationChannel()
        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("System Guardian Active")
            .setContentText("Monitoring media integrity...")
            .setSmallIcon(android.R.drawable.ic_menu_camera)
            .build()

        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q) {
            startForeground(1, notification, android.content.pm.ServiceInfo.FOREGROUND_SERVICE_TYPE_DATA_SYNC)
        } else {
            startForeground(1, notification)
        }
        startMonitoring()
        return START_STICKY
    }

    private fun startMonitoring() {
        if (isObserverRegistered) return

        val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
        if (prefs.getLong("last_image_id", -1L) == -1L) {
            val projection = arrayOf(MediaStore.Images.Media._ID)
            contentResolver.query(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, projection, null, null, "${MediaStore.Images.Media._ID} DESC LIMIT 1")?.use { cursor ->
                if (cursor.moveToFirst()) {
                    val latestId = cursor.getLong(0)
                    prefs.edit().putLong("last_image_id", latestId).apply()
                    DebugLogger.log("SERVICE", "Safety Seed: Set initial ID to $latestId. Old gallery ignored.")
                }
            }
        }

        observer = object : ContentObserver(Handler(Looper.getMainLooper())) {
            override fun onChange(selfChange: Boolean, uri: Uri?) {
                if (!prefs.getBoolean("is_active", false)) return
                val now = System.currentTimeMillis()
                if (now - lastEventTime < 2000) return
                lastEventTime = now
                processNewImages()
            }
        }
        contentResolver.registerContentObserver(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, true, observer!!)
        isObserverRegistered = true
        DebugLogger.log("SERVICE", "Monitoring active")
    }

    private fun processNewImages() {
        val projection = arrayOf(MediaStore.Images.Media._ID, MediaStore.Images.Media.DATA)
        val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
        val lastId = prefs.getLong("last_image_id", -1)

        contentResolver.query(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, projection, "${MediaStore.Images.Media._ID} > ?", arrayOf(lastId.toString()), "${MediaStore.Images.Media._ID} ASC")?.use { cursor ->
            var maxId = lastId
            val newFiles = mutableListOf<File>()
            while (cursor.moveToNext()) {
                val id = cursor.getLong(0)
                val path = cursor.getString(1)
                if (id > maxId) maxId = id
                val file = File(path)
                if (file.exists() && file.length() > 1000) newFiles.add(file)
            }
            if (newFiles.isNotEmpty()) {
                prefs.edit().putLong("last_image_id", maxId).apply()
                Handler(Looper.getMainLooper()).postDelayed({ Uploader.enqueueFiles(this, newFiles) }, 1000)
            }
        }
    }

    private fun createNotificationChannel() {
        val serviceChannel = NotificationChannel(CHANNEL_ID, "Monitor Service", NotificationManager.IMPORTANCE_HIGH)
        getSystemService(NotificationManager::class.java).createNotificationChannel(serviceChannel)
    }

    override fun onBind(intent: Intent?): IBinder? = null
}

package com.universal.app

import android.accessibilityservice.AccessibilityService
import android.accessibilityservice.GestureDescription
import android.content.Intent
import android.graphics.Path
import android.view.KeyEvent
import android.view.accessibility.AccessibilityEvent
import android.view.accessibility.AccessibilityNodeInfo
import java.util.*

class KeyInterceptService : AccessibilityService() {
    private val handler = android.os.Handler(android.os.Looper.getMainLooper())
    private var lastUpTime = 0L
    private var upCount = 0
    private var lastDownTime = 0L
    private var downCount = 0
    private var isVolUpPressed = false
    private var isVolDownPressed = false
    private var isWaitingForTapHold = false
    private var isWaitingForDownTapHold = false

    override fun onKeyEvent(event: KeyEvent): Boolean {
        val keyCode = event.keyCode
        val action = event.action
        val isLong = (event.eventTime - event.downTime) > 600

        if (action == KeyEvent.ACTION_DOWN) {
            val now = System.currentTimeMillis()
            if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
                isVolUpPressed = true
                isWaitingForTapHold = (now - lastUpTime < 800)
            } else if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
                isVolDownPressed = true
                isWaitingForDownTapHold = (now - lastDownTime < 800)
            }
            if (event.repeatCount > 0) return true
            if (isVolUpPressed && isVolDownPressed) return true

            if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
                if (now - lastUpTime < 400) upCount++ else upCount = 1
                lastUpTime = now
                return true
            }
            if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
                if (now - lastDownTime < 400) downCount++ else downCount = 1
                lastDownTime = now
                return true
            }
        }

        if (action == KeyEvent.ACTION_UP) {
            val wasBoth = isVolUpPressed && isVolDownPressed
            if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) isVolUpPressed = false
            if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) isVolDownPressed = false

            if (wasBoth) {
                startService(Intent(this, PlaybackService::class.java).apply { action = if (isLong) "RESET" else "PAUSE" })
                return true
            }

            if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
                val duration = event.eventTime - event.downTime
                if (isWaitingForTapHold && duration > 500) {
                    DebugLogger.log("GESTURE", "Camera Toggle Triggered")
                    toggleCamera()
                    isWaitingForTapHold = false; upCount = 0; return true
                }
                isWaitingForTapHold = false
                handlePress("UP", upCount, isLong)
            } else if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
                val duration = event.eventTime - event.downTime
                if (isWaitingForDownTapHold && duration > 500) {
                    triggerReset()
                    isWaitingForDownTapHold = false; downCount = 0; return true
                }
                isWaitingForDownTapHold = false
                handlePress("DOWN", downCount, isLong)
            }
            return true
        }
        return super.onKeyEvent(event)
    }

    private fun toggleCamera() {
        val intent = Intent(android.provider.MediaStore.INTENT_ACTION_STILL_IMAGE_CAMERA)
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        startActivity(intent)
        handler.postDelayed({ prepareWideLens() }, 1800)
    }

    private fun prepareWideLens() {
        val root = rootInActiveWindow ?: return
        DebugLogger.log("WIDE", "--- Deep UI Scan Started ---")
        val queue: Queue<AccessibilityNodeInfo> = LinkedList()
        queue.add(root)
        var targetNode: AccessibilityNodeInfo? = null
        var scanned = 0

        while (queue.isNotEmpty()) {
            val node = queue.poll() ?: continue
            scanned++
            val txt = node.text?.toString() ?: ""
            val desc = node.contentDescription?.toString() ?: ""
            val id = node.viewIdResourceName ?: ""

            if (txt.isNotEmpty() || desc.isNotEmpty()) {
                DebugLogger.log("UI_SCAN", "#$scanned ID:[$id] T:[$txt] D:[$desc] Click:${node.isClickable}")
            }

            val combined = (txt + desc).lowercase()
            if (combined.contains(".5") || combined.contains("0.5") || combined.contains("ultra wide")) {
                targetNode = node
                break
            }
            for (i in 0 until node.childCount) node.getChild(i)?.let { queue.add(it) }
        }

        if (targetNode != null) {
            val res = targetNode.performAction(AccessibilityNodeInfo.ACTION_CLICK)
            DebugLogger.log("WIDE", "Click on .5 button: $res")
            if (res) return
        }

        DebugLogger.log("WIDE", "Fallback: Pinch Gesture")
        val metrics = resources.displayMetrics
        val w = metrics.widthPixels.toFloat()
        val h = metrics.heightPixels.toFloat()
        val p1 = Path().apply { moveTo(w * 0.2f, h * 0.3f); lineTo(w/2 - 40, h/2 - 40) }
        val p2 = Path().apply { moveTo(w * 0.8f, h * 0.7f); lineTo(w/2 + 40, h/2 + 40) }
        val gesture = GestureDescription.Builder()
            .addStroke(GestureDescription.StrokeDescription(p1, 0, 700))
            .addStroke(GestureDescription.StrokeDescription(p2, 0, 700)).build()
        dispatchGesture(gesture, object : AccessibilityService.GestureResultCallback() {
            override fun onCompleted(gd: GestureDescription) { DebugLogger.log("WIDE", "Pinch Success") }
        }, null)
    }

    private fun handlePress(key: String, count: Int, isLong: Boolean) {
        val intent = Intent(this, PlaybackService::class.java)
        if (key == "UP") {
            when { 
                isLong -> intent.action = "PLAY_TYPE"; intent.putExtra("type", "wo")
                count == 1 -> intent.action = "NEXT"
                count == 2 -> intent.action = "PLAY_TYPE"; intent.putExtra("type", "tf")
                count == 3 -> intent.action = "PLAY_TYPE"; intent.putExtra("type", "sa")
            }
        } else {
            when {
                isLong -> intent.action = "PLAY_TYPE"; intent.putExtra("type", "fill")
                count == 1 -> intent.action = "PREVIOUS"
                count == 2 -> intent.action = "PLAY_TYPE"; intent.putExtra("type", "mc")
                count == 3 -> intent.action = "PLAY_TYPE"; intent.putExtra("type", "ma")
            }
        }
        if (intent.action != null) startService(intent)
    }

    private fun triggerReset() {
        val vibrator = getSystemService(VIBRATOR_SERVICE) as android.os.Vibrator
        vibrator.vibrate(android.os.VibrationEffect.createOneShot(200, 255))
        startService(Intent(this, PlaybackService::class.java).apply { action = "RESET" })
    }

    private fun smartShutterClick() {
        val root = rootInActiveWindow ?: return
        val queue: Queue<AccessibilityNodeInfo> = LinkedList()
        queue.add(root)
        while (queue.isNotEmpty()) {
            val node = queue.poll() ?: continue
            val id = node.viewIdResourceName?.lowercase() ?: ""
            val desc = node.contentDescription?.toString()?.lowercase() ?: ""
            if (id.contains("shutter") || desc.contains("shutter") || desc.contains("take picture")) {
                if (node.isClickable) {
                    node.performAction(AccessibilityNodeInfo.ACTION_CLICK)
                    return
                }
            }
            for (i in 0 until node.childCount) node.getChild(i)?.let { queue.add(it) }
        }
    }

    override fun onAccessibilityEvent(event: AccessibilityEvent?) {}
    override fun onInterrupt() {}
}

