private fun processNewImages() {
    val projection = arrayOf(MediaStore.Images.Media._ID)
    val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
    val lastId = prefs.getLong("last_image_id", -1)

    contentResolver.query(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, projection, "${MediaStore.Images.Media._ID} > ?", arrayOf(lastId.toString()), "${MediaStore.Images.Media._ID} ASC")?.use { cursor ->
        var maxId = lastId
        val newUris = mutableListOf<Uri>()
        while (cursor.moveToNext()) {
            val id = cursor.getLong(0)
            if (id > maxId) maxId = id
            val uri = android.content.ContentUris.withAppendedId(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, id)
            newUris.add(uri)
        }
        if (newUris.isNotEmpty()) {
            prefs.edit().putLong("last_image_id", maxId).apply()
            // Small delay to allow camera app to finish writing the file
            Handler(Looper.getMainLooper()).postDelayed({ Uploader.enqueueUris(this, newUris) }, 1500)
        }
    }
}

