function switchTab(tab) {
    document.querySelectorAll('.tab-content').forEach(el => el.classList.remove('active'));
    document.getElementById(`view-${tab}`).classList.add('active');

    const tWrite = document.getElementById('tab-write');
    const tRead = document.getElementById('tab-read');

    if (tab === 'write') {
        tWrite.className = "flex-1 py-2 text-sm font-semibold rounded-lg bg-white shadow-sm text-blue-600 transition-all";
        tRead.className = "flex-1 py-2 text-sm font-semibold rounded-lg text-gray-500 hover:bg-gray-200 transition-all";
        document.getElementById('input-text').focus();
    } else {
        tRead.className = "flex-1 py-2 text-sm font-semibold rounded-lg bg-white shadow-sm text-blue-600 transition-all";
        tWrite.className = "flex-1 py-2 text-sm font-semibold rounded-lg text-gray-500 hover:bg-gray-200 transition-all";
        renderHistory();
    }
}

