function renderSqlResultTable(data) {
    const output = document.getElementById('sqlResultOutput');
    if (!data || data.length === 0) {
        output.innerHTML = '<div class="p-20 text-center text-slate-500 text-xs uppercase tracking-widest">Empty Result Set</div>';
        return;
    }
    const cols = Object.keys(data[0]);
    let html = '<div class="overflow-auto h-full"><table class="w-full text-left border-collapse">';
    html += '<thead class="sticky top-0 z-10 bg-[#0a0a0a]"><tr>';
    cols.forEach(c => {
        html += '<th class="p-3 border-b border-white/10 text-[9px] font-black uppercase text-blue-500 tracking-tighter">' + c + '</th>';
    });
    html += '</tr></thead><tbody class="divide-y divide-white/5">';
    data.forEach((row, idx) => {
        html += '<tr class="' + (idx % 2 === 0 ? 'bg-transparent' : 'bg-white/[0.01]') + '">';
        cols.forEach(c => {
            const val = row[c];
            let display = val;
            if (val === null) display = '<span class="opacity-20">NULL</span>';
            else if (typeof val === 'object') display = '<span class="text-blue-400/80 underline">JSON</span>';
            else if (typeof val === 'boolean') display = val ? 'TRUE' : 'FALSE';
            html += '<td class="p-3 truncate text-slate-400 border-r border-white/5 result-cell">' + display + '</td>';
        });
        html += '</tr>';
    });
    html += '</tbody></table></div>';
    output.innerHTML = html;
}

