2087 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2088 |     function applyLocalPatch(content, ops) {
2089 |         let lines = content.split('\n');
2090 |         let logs = [];
2091 |         let success = true;
2092 | 
2093 |         if (typeof ops === 'string') {
2094 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2095 |         }
2096 | 
2097 |         ops.forEach(op => {
2098 |             if (op.action === 'comment') return;
2099 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2100 |             
2101 |             if (op.action === 'replace_block') {
2102 |                 // Strategy 1: Exact String Match (Fastest)
2103 |                 const currentStr = lines.join('\n');
2104 |                 if (currentStr.includes(op.find_block)) {
2105 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2106 |                     logs.push('Exact match applied');
2107 |                     return;
2108 |                 }
2109 | 
2110 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2111 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2112 |                 if (searchLines.length === 0) return;
2113 | 
2114 |                 let matchStart = -1;
2115 |                 let matchEnd = -1;
2116 | 
2117 |                 // Scan file lines
2118 |                 for (let i = 0; i < lines.length; i++) {
2119 |                     // If first line matches (ignoring whitespace)
2120 |                     if (lines[i].trim() === searchLines[0]) {
2121 |                         // Check subsequent lines
2122 |                         let allMatch = true;
2123 |                         let fileOffset = 0;
2124 |                         let searchOffset = 1;
2125 |                         
2126 |                         while (searchOffset < searchLines.length) {
2127 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2128 |                             const nextFile = lines[i + fileOffset + 1].trim();
2129 |                             // Skip empty lines in file if they aren't in search block
2130 |                             if (nextFile === '') {
2131 |                                 fileOffset++;
2132 |                                 continue;
2133 |                             }
2134 |                             if (nextFile !== searchLines[searchOffset]) {
2135 |                                 allMatch = false;
2136 |                                 break;
2137 |                             }
2138 |                             fileOffset++;
2139 |                             searchOffset++;
2140 |                         }
2141 | 
2142 |                         if (allMatch) {
2143 |                             matchStart = i;
2144 |                             matchEnd = i + fileOffset;
2145 |                             break;
2146 |                         }
2147 |                     }
2148 |                 }
2149 | 
2150 |                 if (matchStart !== -1) {
2151 |                     // Replace the range of lines
2152 |                     const replacement = op.replace_with.split('\n');
2153 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2154 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2155 |                 } else {
2156 |                     success = false;
2157 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2158 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2159 |                 }
2160 |             }
2161 |         });
2162 |         return { content: lines.join('\n'), success, logs };
2163 |     }
