4879 |     function formatBytes(bytes) {
4880 |         if (!bytes) return '0 B';
4881 |         const k = 1024;
4882 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4883 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4884 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4885 |     }
