4887 |     function timeAgo(dateString) {
4888 |         const date = new Date(dateString);
4889 |         const now = new Date();
4890 |         const seconds = Math.floor((now - date) / 1000);
4891 |         if (seconds < 10) return 'just now';
4892 |         if (seconds < 60) return seconds + 's ago';
4893 |         const minutes = Math.floor(seconds / 60);
4894 |         if (minutes < 60) return minutes + 'm ago';
4895 |         const hours = Math.floor(minutes / 60);
4896 |         if (hours < 24) return hours + 'h ago';
4897 |         return date.toLocaleDateString();
4898 |     }
