5097 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5098 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5099 |         
5100 |         const navItems = document.querySelectorAll('.nav-item');
5101 |         switchTab(tabId, navItems[navIndex]);
5102 | 
5103 |         const scrollContainer = document.querySelector('.main-view');
5104 |         let retryCount = 0;
5105 |         const MAX_RETRIES = 5;
5106 | 
5107 |         const attemptNavigation = async () => {
5108 |             const element = document.querySelector(selector);
5109 |             
5110 |             if (element) {
5111 |                 console.log("[DeepJump] Element found. Scrolling...");
5112 |                 
5113 |                 // Wait for any tab transition animations
5114 |                 await new Promise(r => setTimeout(r, 300));
5115 | 
5116 |                 let offsetTop = 0;
5117 |                 let curr = element;
5118 |                 while (curr && curr !== scrollContainer) {
5119 |                     offsetTop += curr.offsetTop;
5120 |                     curr = curr.offsetParent;
5121 |                 }
5122 | 
5123 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5124 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5125 | 
5126 |                 // Visual Highlight
5127 |                 element.style.transition = 'all 0.5s ease';
5128 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5129 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5130 |                 setTimeout(() => {
5131 |                     element.style.backgroundColor = '';
5132 |                     element.style.boxShadow = '';
5133 |                 }, 3000);
5134 |                 
5135 |                 console.groupEnd();
5136 |                 return true;
5137 |             }
5138 | 
5139 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5140 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5141 |                 retryCount++;
5142 |                 showGlobalToast("🔍 Searching deeper...");
5143 |                 
5144 |                 await loadMoreFn(); 
5145 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5146 |                 return attemptNavigation();
5147 |             }
5148 | 
5149 |             console.error("[DeepJump] Failed: Element not found after retries.");
5150 |             showGlobalToast("Entry not found in recent history.", true);
5151 |             console.groupEnd();
5152 |             return false;
5153 |         };
5154 | 
5155 |         setTimeout(attemptNavigation, 100);
5156 |     }
