6212 |         diffRight.setValue("Loading...", -1);
6213 | 
6214 |         try {
6215 |             let leftContent = "", rightContent = "";
6216 | 
6217 |             if (forcedLeft !== null && forcedRight !== null) {
6218 |                 leftContent = forcedLeft;
6219 |                 rightContent = forcedRight;
6220 |             } else {
6221 |                 const rightRef = data.commit_sha || 'HEAD';
6222 |                 const leftRef = rightRef + '^';
