6246 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
6247 |             
6248 |             diffLeft.session.setMode(mode);
6249 |             diffLeft.setValue(leftContent, -1);
6250 |             
6251 |             diffRight.session.setMode(mode);
6252 |             diffRight.setValue(rightContent, -1);
6253 | 
6254 |             const Range = ace.require('ace/range').Range;
6255 | 
6256 |             // Helper to get Range from String Index
6257 |             const getRangeFromText = (session, searchText) => {
6258 |                 const fullText = session.getValue();
6259 |                 // 1. Try Exact Match
6260 |                 let startIdx = fullText.indexOf(searchText);
6261 |                 
6262 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
