7182 |     function extractTableNames(sql) {
7183 |         if (!sql) return [];
7184 |         const tables = [];
7185 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7186 |         
7187 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7188 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7189 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7190 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7191 | 
7192 |         let match;
7193 |         while ((match = fromRegex.exec(sql)) !== null) {
7194 |             const name = match[1];
7195 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7196 |                 tables.push(name);
7197 |             }
7198 |         }
7199 |         
7200 |         while ((match = metaRegex.exec(sql)) !== null) {
7201 |             const name = match[1];
7202 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7203 |                 tables.push(name);
7204 |             }
7205 |         }
7206 | 
7207 |         return tables;
7208 |     }
7209 | 
7210 |     function convertToCSV(resultObj) {
7211 |         const data = resultObj.data || [];
7212 |         if (!data.length) return '';
7213 |         
7214 |         const tables = extractTableNames(resultObj.sql);
7215 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7216 | 
7217 |         const headers = Object.keys(data[0]);
7218 |         const rows = data.map(row => 
7219 |             headers.map(header => {
7220 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7221 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7222 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7223 |             }).join(',')
7224 |         );
7225 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7226 |     }
